const items = $input.all();
if (items.length === 0) {
  return [{ json: { text: '📭 Nenhum abastecimento ainda.' } }];
}

let msg = '📋 *ÚLTIMOS ABASTECIMENTOS*\n\n';
items.forEach((item, i) => {
  const d = new Date(item.json.criado_em).toLocaleDateString('pt-BR');
  msg += `${i+1}. 🚗 ${item.json.placa} | ${item.json.km}km | ${item.json.litros}L\n   📅 ${d}\n`;
});

return [{ json: { text: msg } }];

const state = JSON.parse($('Buscar Estado Redis').item.json.value);
const msg = $('WhatsApp Trigger').item.json.messageText || '';
const userId = $('WhatsApp Trigger').item.json.chatId.replace('@s.whatsapp.net', '');
const senderName = $('WhatsApp Trigger').item.json.pushName || 'Usuário';
const hasMedia = !!$('WhatsApp Trigger').item.json.media;

let response = '';
let newState = null;
const data = state.data || {};

function isValidPlaca(p) {
  return /^[A-Z]{3}[0-9][A-Z][0-9]{2}$/.test(p) || /^[A-Z]{3}[0-9]{4}$/.test(p);
}

switch (state.state) {
  case 'aguardando_placa':
    const placa = msg.toUpperCase().trim();
    if (!isValidPlaca(placa)) {
      response = '❌ Placa inválida! Use: ABC1D23 ou ABC1234';
    } else {
      newState = { state: 'aguardando_km', data: { placa } };
      response = `✅ Placa *${placa}*!\n\n2️⃣ Informe a *KM ATUAL*:`;
    }
    break;

  case 'aguardando_km':
    const km = parseInt(msg.trim());
    if (isNaN(km) || km <= 0) {
      response = '❌ KM inválida! Digite apenas números';
    } else {
      newState = { state: 'aguardando_litros', data: { ...data, km } };
      response = `✅ KM *${km}*!\n\n3️⃣ Informe os *LITROS* (ex: 45.5):`;
    }
    break;

  case 'aguardando_litros':
    const litros = parseFloat(msg.trim().replace(',', '.'));
    if (isNaN(litros) || litros <= 0) {
      response = '❌ Litros inválidos! Digite um número';
    } else {
      newState = { state: 'aguardando_foto_odometro', data: { ...data, litros } };
      response = `✅ *${litros}L*!\n\n4️⃣ Envie a *FOTO DO ODÔMETRO*:`;
    }
    break;

  case 'aguardando_foto_odometro':
    if (!hasMedia) {
      response = '⚠️ Envie a FOTO DO ODÔMETRO (📎)';
    } else {
      newState = { state: 'aguardando_foto_abastecimento', data: { ...data, foto_odometro: `odo_${Date.now()}.jpg` } };
      response = '✅ Foto recebida!\n\n5️⃣ Envie a *FOTO DO ABASTECIMENTO*:';
    }
    break;

  case 'aguardando_foto_abastecimento':
    if (!hasMedia) {
      response = '⚠️ Envie a FOTO DO ABASTECIMENTO (📎)';
    } else {
      response = `✅ *ABASTECIMENTO REGISTRADO!*\n\n🚗 Placa: ${data.placa}\n📏 KM: ${data.km}\n⛽ Litros: ${data.litros}L\n📅 ${new Date().toLocaleDateString('pt-BR')}`;
      newState = { state: 'salvar', data: { ...data, foto_abastecimento: `abs_${Date.now()}.jpg` } };
    }
    break;
}

return [{ 
  json: { 
    userId, 
    senderName,
    response, 
    newState: newState ? JSON.stringify(newState) : null,
    shouldDelete: state.state === 'aguardando_foto_abastecimento' && hasMedia
  } 
}];
